import scala.collection.mutable

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val visited = Array.ofDim[Boolean](m, n)
  var count = 0L
  val directions = List[(Int, Int)]((-1, 0), (1, 0), (0, -1), (0, 1))

  for (i <- 0 until m) {
    for (j <- 0 until n) {
      if (grid(i)(j) > 0 && !visited(i)(j)) {
        val queue = mutable.Deque[(Int, Int)]()
        queue += (i, j)
        visited(i)(j) = true
        var sum = grid(i)(j)
        while (queue.nonEmpty) {
          val (x, y) = queue.head
          queue.dequeue()
          for ((dx, dy) <- directions) {
            val nx = x + dx
            val ny = y + dy
            if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited(nx)(ny) && grid(nx)(ny) > 0) {
              visited(nx)(ny) = true
              sum += grid(nx)(ny)
              queue += (nx, ny)
            }
          }
        }
        if (sum % k == 0) count += 1
      }
    }
  }
  count
}
